import{_ as t,o as a,c as i,ag as n}from"./chunks/framework.BqfgOMAh.js";const u=JSON.parse('{"title":"Widget Skill","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/widget-skill.md","filePath":"en/guide/widget-skill.md"}'),r={name:"en/guide/widget-skill.md"};function s(l,e,o,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="widget-skill" tabindex="-1">Widget Skill <a class="header-anchor" href="#widget-skill" aria-label="Permalink to &quot;Widget Skill&quot;">​</a></h1><p>Widget Skill is the experimental UMG Widget Blueprint capability introduced in NexusFlow 0.2.0. It targets HUDs, panels, menus, status bars, and similar UI assets, allowing agents to create and modify Widget Blueprints through structured definitions.</p><blockquote><p>This is currently an MVP / experimental feature. Start with small UIs, local changes, and tasks that can be verified through readback.</p></blockquote><h2 id="what-it-can-do" tabindex="-1">What It Can Do <a class="header-anchor" href="#what-it-can-do" aria-label="Permalink to &quot;What It Can Do&quot;">​</a></h2><ul><li>Create Widget Blueprints from scratch.</li><li>Read existing Widget Blueprint structure and layout information.</li><li>Patch existing widget text, colors, percentages, slot data, event declarations, and binding declarations.</li><li>Rewrite the full Designer tree or a specific container branch.</li><li>Capture real preview screenshots when available.</li><li>Work with the Blueprint Skill to add events, variables, functions, and EventGraph logic.</li></ul><h2 id="main-actions" tabindex="-1">Main Actions <a class="header-anchor" href="#main-actions" aria-label="Permalink to &quot;Main Actions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>generate_widget_blueprint</code></td><td>Create a complete Widget Blueprint</td></tr><tr><td><code>read_widget_blueprint</code></td><td>Read structure, layout, and diagnostics</td></tr><tr><td><code>write_widget_tree</code></td><td>Replace the full Designer tree or a container branch</td></tr><tr><td><code>patch_widget_tree</code></td><td>Modify property-level data on existing widgets</td></tr><tr><td><code>capture_widget_preview</code></td><td>Capture a real preview screenshot</td></tr></tbody></table><h2 id="recommended-workflow" tabindex="-1">Recommended Workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended Workflow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Decide the UI type and viewport size.</span></span>
<span class="line"><span>2. Use the root Canvas for a few region containers such as Header, Content, Footer, or Modal.</span></span>
<span class="line"><span>3. Use Border, VerticalBox, HorizontalBox, ScrollBox, and SizeBox inside regions.</span></span>
<span class="line"><span>4. Give important widgets stable IDs; mark interactive widgets with variable.is_variable=true.</span></span>
<span class="line"><span>5. Run generate_widget_blueprint or write_widget_tree.</span></span>
<span class="line"><span>6. Use read_widget_blueprint to verify structure and layout diagnostics.</span></span>
<span class="line"><span>7. If events or bindings are needed, use the Blueprint Skill to add Graph logic.</span></span>
<span class="line"><span>8. Verify through compile, save, readback, or screenshots.</span></span></code></pre></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Widget Tree and Blueprint Graph are separate layers: Designer widgets belong in <code>widget_tree</code>; events, functions, variables, and graph logic belong in the general Blueprint definition.</li><li>Use the root Canvas for region containers; avoid scattering many TextBlocks or Buttons directly under it.</li><li>Use <code>patch_widget_tree</code> for small property-level edits; use <code>write_widget_tree</code> for hierarchy changes.</li><li>A successful write is not enough; verify the final UE state through <code>read_widget_blueprint</code> or screenshots.</li><li>For complex UIs, generate the static structure first, then add interaction logic incrementally.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./mcp">Use NexusFlow from IDEs / Agents</a>: use Widget Skill from external IDEs.</li><li><a href="./blueprint-operations">Blueprint Operations</a>: learn the general Blueprint Graph capabilities.</li></ul>`,13)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
